import SwiftUI
import AppKit
import AIUsagesTrackersLib

enum VendorBranding {
    struct Brand: Equatable, Sendable {
        let assetName: String
        let displayName: String
        let tintHex: String
    }

    static func brand(for vendor: Vendor) -> Brand? {
        switch vendor {
        case .claude:
            Brand(
                assetName: "claude-mark",
                displayName: "Claude Code",
                tintHex: "DA7756"
            )
        case .codex:
            Brand(
                assetName: "codex-mark",
                displayName: "Codex",
                tintHex: "10A37F"
            )
        default:
            nil
        }
    }

    static func displayName(for vendor: Vendor) -> String {
        brand(for: vendor)?.displayName ?? vendor.rawValue
    }

    static func tint(for vendor: Vendor) -> Color? {
        guard let tintHex = brand(for: vendor)?.tintHex else { return nil }
        return Color(hex: tintHex)
    }

    static func icon(for vendor: Vendor) -> NSImage? {
        guard let assetName = brand(for: vendor)?.assetName else { return nil }
        return loadTemplateImage(named: assetName)
    }

    /// Returns a tinted, non-template copy of the vendor icon at the requested height.
    /// Uses the brand's `tintHex` as fill color and the template PDF as an alpha mask.
    static func tintedNSImage(for vendor: Vendor, height: CGFloat) -> NSImage? {
        guard let template = icon(for: vendor),
              let brand = brand(for: vendor),
              let tintColor = NSColor(hex: brand.tintHex) else { return nil }
        let aspectRatio = template.size.height > 0
            ? template.size.width / template.size.height : 1
        let size = NSSize(width: ceil(height * aspectRatio), height: ceil(height))
        let result = NSImage(size: size)
        result.lockFocus()
        tintColor.setFill()
        NSRect(origin: .zero, size: size).fill()
        template.draw(
            in: NSRect(origin: .zero, size: size),
            from: .zero,
            operation: .destinationIn,
            fraction: 1.0
        )
        result.unlockFocus()
        result.isTemplate = false
        return result
    }

    private static func loadTemplateImage(named assetName: String) -> NSImage? {
        guard let url = Bundle.module.url(
            forResource: assetName,
            withExtension: "pdf",
            subdirectory: "VendorBranding"
        ), let image = NSImage(contentsOf: url) else {
            return nil
        }

        image.isTemplate = true
        return image
    }
}

struct VendorIconView: View {
    let vendor: Vendor
    var size: CGFloat = 14

    var body: some View {
        if let image = VendorBranding.icon(for: vendor),
           let tint = VendorBranding.tint(for: vendor) {
            Image(nsImage: image)
                .renderingMode(.template)
                .resizable()
                .scaledToFit()
                .frame(width: size, height: size)
                .foregroundStyle(tint)
                .accessibilityHidden(true)
        }
    }
}

struct VendorLabelView: View {
    let vendor: Vendor
    var iconSize: CGFloat = 14

    var body: some View {
        HStack(spacing: 6) {
            VendorIconView(vendor: vendor, size: iconSize)
            Text(VendorBranding.displayName(for: vendor))
        }
    }
}

private extension Color {
    init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = Double((value >> 16) & 0xFF) / 255.0
        let green = Double((value >> 8) & 0xFF) / 255.0
        let blue = Double(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue)
    }
}

private extension NSColor {
    convenience init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = CGFloat((value >> 16) & 0xFF) / 255.0
        let green = CGFloat((value >> 8) & 0xFF) / 255.0
        let blue = CGFloat(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue, alpha: 1.0)
    }
}

import AppKit
import AIUsagesTrackersLib

/// Rasterises the full menu bar label into a non-template `NSImage`.
/// MenuBarExtra's label was unusable: template tinting stripped the per-tier
/// dot colors, and mixed HStacks silently truncated segments past the first.
/// With a custom `NSStatusItem`, we control `isTemplate = false` so hues
/// survive and we pick the text color from the status button's effective
/// appearance (which tracks the menu bar, not the app).
@MainActor
enum MenuBarLabelRenderer {
    private static let font: NSFont = .menuBarFont(ofSize: 0)
    private static let dot = "● "
    private static let horizontalPadding: CGFloat = 4
    private static let height: CGFloat = 18

    static func render(
        segments: [MenuBarSegment],
        separator: String,
        fallbackText: String,
        isDarkMenuBar: Bool
    ) -> NSImage {
        let textColor: NSColor = isDarkMenuBar ? .white : .black
        let attributed = attributedString(
            segments: segments,
            separator: separator,
            fallbackText: fallbackText,
            textColor: textColor
        )
        let textSize = attributed.size()
        let width = ceil(textSize.width) + horizontalPadding * 2
        let size = NSSize(width: max(width, 1), height: height)
        let image = NSImage(size: size)
        image.lockFocus()
        let textY = (height - ceil(textSize.height)) / 2
        attributed.draw(at: NSPoint(x: horizontalPadding, y: textY))
        image.unlockFocus()
        image.isTemplate = false
        return image
    }

    private static func attributedString(
        segments: [MenuBarSegment],
        separator: String,
        fallbackText: String,
        textColor: NSColor
    ) -> NSAttributedString {
        guard !segments.isEmpty else {
            return NSAttributedString(
                string: fallbackText,
                attributes: [.font: font, .foregroundColor: textColor]
            )
        }
        let result = NSMutableAttributedString()
        for (index, segment) in segments.enumerated() {
            if index > 0, !separator.isEmpty {
                result.append(NSAttributedString(
                    string: separator,
                    attributes: [.font: font, .foregroundColor: textColor]
                ))
            }
            if let vendor = segment.vendorIcon,
               let icon = VendorBranding.tintedNSImage(for: vendor, height: font.capHeight) {
                let attachment = NSTextAttachment()
                attachment.image = icon
                attachment.bounds = CGRect(x: 0, y: 0, width: icon.size.width, height: icon.size.height)
                result.append(NSAttributedString(attachment: attachment))
                result.append(NSAttributedString(
                    string: "\u{2009}",
                    attributes: [.font: font, .foregroundColor: textColor]
                ))
            }
            if segment.showDot {
                let dotColor = segment.tier?.nsColor ?? textColor
                result.append(NSAttributedString(
                    string: dot,
                    attributes: [.font: font, .foregroundColor: dotColor]
                ))
            }
            result.append(NSAttributedString(
                string: segment.text,
                attributes: [.font: font, .foregroundColor: textColor]
            ))
        }
        return result
    }
}

